const binaryAssets: Record<string, { contentType: string; cacheControl: string; body: string }> = {
  "/favicon.ico": { contentType: "image/x-icon", cacheControl: "public, max-age=31536000, immutable", body: "" },
  "/favicon-16x16.png": { contentType: "image/png", cacheControl: "public, max-age=31536000, immutable", body: "" },
  "/favicon-32x32.png": { contentType: "image/png", cacheControl: "public, max-age=31536000, immutable", body: "" },
  "/apple-touch-icon.png": { contentType: "image/png", cacheControl: "public, max-age=31536000, immutable", body: "" },
  "/android-chrome-192x192.png": { contentType: "image/png", cacheControl: "public, max-age=31536000, immutable", body: "" },
  "/android-chrome-512x512.png": { contentType: "image/png", cacheControl: "public, max-age=31536000, immutable", body: "" },
};

const manifest = "{\"name\":\"Droplet Auth\",\"short_name\":\"Droplet Auth\",\"icons\":[{\"src\":\"/android-chrome-192x192.png\",\"sizes\":\"192x192\",\"type\":\"image/png\"},{\"src\":\"/android-chrome-512x512.png\",\"sizes\":\"512x512\",\"type\":\"image/png\"}],\"theme_color\":\"#f6f7f9\",\"background_color\":\"#f6f7f9\",\"display\":\"standalone\"}";

export function handleAsset(pathname: string): Response | null {
  if (pathname === "/site.webmanifest") {
    return new Response(manifest, { headers: assetHeaders("application/manifest+json; charset=utf-8", "public, max-age=300") });
  }

  const asset = binaryAssets[pathname];
  if (!asset) return null;
  return new Response(base64ToArrayBuffer(asset.body), { headers: assetHeaders(asset.contentType, asset.cacheControl) });
}

function assetHeaders(contentType: string, cacheControl: string): Headers {
  return new Headers({
    "content-type": contentType,
    "cache-control": cacheControl,
  });
}

function base64ToArrayBuffer(value: string): ArrayBuffer {
  const binary = atob(value);
  const bytes = new Uint8Array(binary.length);
  for (let index = 0; index < binary.length; index += 1) bytes[index] = binary.charCodeAt(index);
  return bytes.buffer.slice(bytes.byteOffset, bytes.byteOffset + bytes.byteLength) as ArrayBuffer;
}
